fn main() {
    let result: Result<i32, &str> = Err("Error!");

    match result {
        Ok(val) => println!("Value: {}", val),
        Err(e) if e == "Error!" => println!("Caught error: {}", e),
        _ => println!("Handled all errors")
    }
